/**
 * Tests for export-quality-settings module
 * Feature #75: 4K Export & Quality Settings
 */

import {
  RESOLUTION_PRESETS,
  PLATFORM_PRESETS,
  FORMAT_OPTIONS,
  QUALITY_PRESETS,
  PLAN_LIMITS,
  calculateBitrate,
  estimateFileSize,
  formatFileSize,
  getResolutionPreset,
  getPlatformPreset,
  getFormatOption,
  getQualityPreset,
  isResolutionAllowed,
  isFormatAllowed,
  getAvailableResolutions,
  getAvailablePlatformPresets,
  buildFFmpegSettings,
  buildConfigFromPlatform,
  inferQualityFromBitrate,
  validateExportConfig,
  getDefaultConfig,
  estimateExportDuration,
  formatEstimatedDuration,
  type ExportConfiguration,
  type UserPlan,
} from '@lib/export/export-quality-settings';

// ─── Constants Tests ───────────────────────────────────────────────────

describe('export-quality-settings constants', () => {
  test('RESOLUTION_PRESETS has 4 entries (480p, 720p, 1080p, 4K)', () => {
    expect(RESOLUTION_PRESETS).toHaveLength(4);
    const ids = RESOLUTION_PRESETS.map(r => r.id);
    expect(ids).toEqual(['480p', '720p', '1080p', '4k']);
  });

  test('all resolution presets have valid dimensions', () => {
    for (const preset of RESOLUTION_PRESETS) {
      expect(preset.width).toBeGreaterThan(0);
      expect(preset.height).toBeGreaterThan(0);
      expect(preset.label).toBeTruthy();
      expect(preset.aspectRatio).toBeTruthy();
    }
  });

  test('only 4K requires premium', () => {
    const premium = RESOLUTION_PRESETS.filter(r => r.requiresPremium);
    expect(premium).toHaveLength(1);
    expect(premium[0].id).toBe('4k');
  });

  test('PLATFORM_PRESETS has entries for major platforms', () => {
    expect(PLATFORM_PRESETS.length).toBeGreaterThanOrEqual(7);
    const ids = PLATFORM_PRESETS.map(p => p.id);
    expect(ids).toContain('youtube-1080p');
    expect(ids).toContain('instagram-feed');
    expect(ids).toContain('tiktok');
    expect(ids).toContain('linkedin');
  });

  test('all platform presets have valid configs', () => {
    for (const preset of PLATFORM_PRESETS) {
      expect(preset.width).toBeGreaterThan(0);
      expect(preset.height).toBeGreaterThan(0);
      expect(preset.fps).toBeGreaterThan(0);
      expect(preset.recommendedBitrateKbps).toBeGreaterThan(0);
      expect(['mp4', 'webm', 'mov']).toContain(preset.format);
      expect(['h264', 'h265', 'vp9']).toContain(preset.codec);
    }
  });

  test('FORMAT_OPTIONS covers mp4, webm, mov', () => {
    expect(FORMAT_OPTIONS).toHaveLength(3);
    const ids = FORMAT_OPTIONS.map(f => f.id);
    expect(ids).toEqual(['mp4', 'webm', 'mov']);
  });

  test('QUALITY_PRESETS covers all levels', () => {
    expect(QUALITY_PRESETS).toHaveLength(4);
    const ids = QUALITY_PRESETS.map(q => q.id);
    expect(ids).toEqual(['low', 'medium', 'high', 'ultra']);
  });

  test('quality CRF values decrease with higher quality', () => {
    for (let i = 1; i < QUALITY_PRESETS.length; i++) {
      expect(QUALITY_PRESETS[i].crf).toBeLessThan(QUALITY_PRESETS[i - 1].crf);
    }
  });

  test('PLAN_LIMITS covers all plans', () => {
    const plans: UserPlan[] = ['free', 'starter', 'pro', 'enterprise'];
    for (const plan of plans) {
      expect(PLAN_LIMITS[plan]).toBeDefined();
      expect(PLAN_LIMITS[plan].maxWidth).toBeGreaterThan(0);
    }
  });

  test('plan limits increase with plan tier', () => {
    expect(PLAN_LIMITS.free.maxWidth).toBeLessThanOrEqual(PLAN_LIMITS.starter.maxWidth);
    expect(PLAN_LIMITS.starter.maxWidth).toBeLessThanOrEqual(PLAN_LIMITS.pro.maxWidth);
    expect(PLAN_LIMITS.pro.maxWidth).toBeLessThanOrEqual(PLAN_LIMITS.enterprise.maxWidth);
  });
});

// ─── calculateBitrate Tests ────────────────────────────────────────────

describe('calculateBitrate', () => {
  const mediumQuality = QUALITY_PRESETS[1]; // medium, multiplier=1.0

  test('returns positive number for valid inputs', () => {
    const bitrate = calculateBitrate(1920, 1080, mediumQuality);
    expect(bitrate).toBeGreaterThan(0);
  });

  test('higher resolution = higher bitrate', () => {
    const bitrate720 = calculateBitrate(1280, 720, mediumQuality);
    const bitrate1080 = calculateBitrate(1920, 1080, mediumQuality);
    const bitrate4k = calculateBitrate(3840, 2160, mediumQuality);
    expect(bitrate1080).toBeGreaterThan(bitrate720);
    expect(bitrate4k).toBeGreaterThan(bitrate1080);
  });

  test('higher quality multiplier = higher bitrate', () => {
    const low = calculateBitrate(1920, 1080, QUALITY_PRESETS[0]);
    const high = calculateBitrate(1920, 1080, QUALITY_PRESETS[2]);
    expect(high).toBeGreaterThan(low);
  });

  test('higher fps = higher bitrate', () => {
    const fps30 = calculateBitrate(1920, 1080, mediumQuality, 30);
    const fps60 = calculateBitrate(1920, 1080, mediumQuality, 60);
    expect(fps60).toBeGreaterThan(fps30);
  });

  test('result is clamped to reasonable range', () => {
    // Very small resolution
    const tiny = calculateBitrate(64, 64, QUALITY_PRESETS[0]);
    expect(tiny).toBeGreaterThanOrEqual(500);

    // Very large resolution
    const huge = calculateBitrate(7680, 4320, QUALITY_PRESETS[3]);
    expect(huge).toBeLessThanOrEqual(50000);
  });
});

// ─── estimateFileSize Tests ────────────────────────────────────────────

describe('estimateFileSize', () => {
  test('returns 0 for 0 duration', () => {
    expect(estimateFileSize(0, 5000, 192)).toBe(0);
  });

  test('returns 0 for negative duration', () => {
    expect(estimateFileSize(-10, 5000, 192)).toBe(0);
  });

  test('returns positive number for valid inputs', () => {
    const size = estimateFileSize(60, 5000, 192);
    expect(size).toBeGreaterThan(0);
  });

  test('longer duration = larger file', () => {
    const short = estimateFileSize(30, 5000, 192);
    const long = estimateFileSize(300, 5000, 192);
    expect(long).toBeGreaterThan(short);
  });

  test('higher bitrate = larger file', () => {
    const low = estimateFileSize(60, 2000, 128);
    const high = estimateFileSize(60, 10000, 256);
    expect(high).toBeGreaterThan(low);
  });

  test('without audio is smaller', () => {
    const withAudio = estimateFileSize(60, 5000, 192, true);
    const withoutAudio = estimateFileSize(60, 5000, 192, false);
    expect(withAudio).toBeGreaterThan(withoutAudio);
  });

  test('60s at 5000kbps is roughly 37.5 MB', () => {
    const size = estimateFileSize(60, 5000, 192, true);
    const mb = size / (1024 * 1024);
    // 5000kbps + 192kbps = 5192kbps ≈ 649KB/s × 60s ≈ 38MB + 5% overhead
    expect(mb).toBeGreaterThan(30);
    expect(mb).toBeLessThan(50);
  });
});

// ─── formatFileSize Tests ──────────────────────────────────────────────

describe('formatFileSize', () => {
  test('formats 0', () => {
    expect(formatFileSize(0)).toBe('0 B');
  });

  test('formats bytes', () => {
    expect(formatFileSize(512)).toBe('512 B');
  });

  test('formats kilobytes', () => {
    expect(formatFileSize(1024)).toBe('1.0 KB');
    expect(formatFileSize(2560)).toBe('2.5 KB');
  });

  test('formats megabytes', () => {
    expect(formatFileSize(1048576)).toBe('1.0 MB');
    expect(formatFileSize(5 * 1024 * 1024)).toBe('5.0 MB');
  });

  test('formats gigabytes', () => {
    expect(formatFileSize(1073741824)).toBe('1.0 GB');
    expect(formatFileSize(2.5 * 1024 * 1024 * 1024)).toBe('2.5 GB');
  });

  test('negative returns 0 B', () => {
    expect(formatFileSize(-100)).toBe('0 B');
  });
});

// ─── Lookup Functions ──────────────────────────────────────────────────

describe('lookup functions', () => {
  test('getResolutionPreset finds by ID', () => {
    expect(getResolutionPreset('1080p')?.width).toBe(1920);
    expect(getResolutionPreset('4k')?.width).toBe(3840);
    expect(getResolutionPreset('nonexistent')).toBeUndefined();
  });

  test('getPlatformPreset finds by ID', () => {
    expect(getPlatformPreset('youtube-1080p')?.width).toBe(1920);
    expect(getPlatformPreset('tiktok')?.aspectRatio).toBe('9:16');
    expect(getPlatformPreset('nonexistent')).toBeUndefined();
  });

  test('getFormatOption finds by ID', () => {
    expect(getFormatOption('mp4')?.label).toBe('MP4');
    expect(getFormatOption('webm')?.defaultCodec).toBe('vp9');
    expect(getFormatOption('avi' as 'mp4')).toBeUndefined();
  });

  test('getQualityPreset finds by ID', () => {
    expect(getQualityPreset('high')?.crf).toBe(18);
    expect(getQualityPreset('ultra')?.ffmpegPreset).toBe('veryslow');
    expect(getQualityPreset('extreme' as 'low')).toBeUndefined();
  });
});

// ─── Plan-based Access Control ─────────────────────────────────────────

describe('plan-based access control', () => {
  test('free plan only allows up to 720p', () => {
    expect(isResolutionAllowed(RESOLUTION_PRESETS[0], 'free')).toBe(true); // 480p
    expect(isResolutionAllowed(RESOLUTION_PRESETS[1], 'free')).toBe(true); // 720p
    expect(isResolutionAllowed(RESOLUTION_PRESETS[2], 'free')).toBe(false); // 1080p
    expect(isResolutionAllowed(RESOLUTION_PRESETS[3], 'free')).toBe(false); // 4K
  });

  test('starter plan allows up to 1080p', () => {
    expect(isResolutionAllowed(RESOLUTION_PRESETS[2], 'starter')).toBe(true);
    expect(isResolutionAllowed(RESOLUTION_PRESETS[3], 'starter')).toBe(false);
  });

  test('pro plan allows 4K', () => {
    expect(isResolutionAllowed(RESOLUTION_PRESETS[3], 'pro')).toBe(true);
  });

  test('free plan only allows mp4', () => {
    expect(isFormatAllowed('mp4', 'free')).toBe(true);
    expect(isFormatAllowed('webm', 'free')).toBe(false);
    expect(isFormatAllowed('mov', 'free')).toBe(false);
  });

  test('pro plan allows all formats', () => {
    expect(isFormatAllowed('mp4', 'pro')).toBe(true);
    expect(isFormatAllowed('webm', 'pro')).toBe(true);
    expect(isFormatAllowed('mov', 'pro')).toBe(true);
  });

  test('getAvailableResolutions returns correct for each plan', () => {
    expect(getAvailableResolutions('free')).toHaveLength(2);
    expect(getAvailableResolutions('starter')).toHaveLength(3);
    expect(getAvailableResolutions('pro')).toHaveLength(4);
    expect(getAvailableResolutions('enterprise')).toHaveLength(4);
  });

  test('getAvailablePlatformPresets respects plan limits', () => {
    const freePresets = getAvailablePlatformPresets('free');
    const proPresets = getAvailablePlatformPresets('pro');
    expect(proPresets.length).toBeGreaterThanOrEqual(freePresets.length);

    // Free plan should not include YouTube 4K
    const freeIds = freePresets.map(p => p.id);
    expect(freeIds).not.toContain('youtube-4k');
  });
});

// ─── buildFFmpegSettings Tests ─────────────────────────────────────────

describe('buildFFmpegSettings', () => {
  const makeConfig = (overrides: Partial<ExportConfiguration> = {}): ExportConfiguration => ({
    resolution: RESOLUTION_PRESETS[2], // 1080p
    format: FORMAT_OPTIONS[0], // mp4
    quality: QUALITY_PRESETS[1], // medium
    codec: 'h264',
    fps: 30,
    customBitrateKbps: null,
    includeAudio: true,
    ...overrides,
  });

  test('builds valid settings for 1080p mp4', () => {
    const settings = buildFFmpegSettings(makeConfig());
    expect(settings.width).toBe(1920);
    expect(settings.height).toBe(1080);
    expect(settings.videoCodec).toBe('libx264');
    expect(settings.audioCodec).toBe('aac');
    expect(settings.fps).toBe(30);
    expect(settings.format).toBe('mp4');
    expect(settings.pixelFormat).toBe('yuv420p');
    expect(settings.crf).toBe(23);
    expect(settings.preset).toBe('medium');
  });

  test('uses custom bitrate when specified', () => {
    const settings = buildFFmpegSettings(makeConfig({ customBitrateKbps: 10000 }));
    expect(settings.videoBitrateKbps).toBe(10000);
  });

  test('calculates bitrate when not specified', () => {
    const settings = buildFFmpegSettings(makeConfig());
    expect(settings.videoBitrateKbps).toBeGreaterThan(0);
  });

  test('webm format uses correct codecs', () => {
    const settings = buildFFmpegSettings(
      makeConfig({ format: FORMAT_OPTIONS[1], codec: 'vp9' }),
    );
    expect(settings.videoCodec).toBe('libvpx-vp9');
    expect(settings.audioCodec).toBe('libopus');
    expect(settings.format).toBe('webm');
  });

  test('H.265 adds hvc1 tag', () => {
    const settings = buildFFmpegSettings(makeConfig({ codec: 'h265' }));
    expect(settings.videoCodec).toBe('libx265');
    expect(settings.additionalFlags).toContain('-tag:v');
    expect(settings.additionalFlags).toContain('hvc1');
  });

  test('4K adds buffer settings', () => {
    const settings = buildFFmpegSettings(
      makeConfig({ resolution: RESOLUTION_PRESETS[3] }),
    );
    expect(settings.width).toBe(3840);
    expect(settings.additionalFlags).toContain('-bufsize');
    expect(settings.additionalFlags).toContain('-maxrate');
  });

  test('VP9 high quality adds row-mt flag', () => {
    const settings = buildFFmpegSettings(
      makeConfig({
        format: FORMAT_OPTIONS[1],
        codec: 'vp9',
        quality: QUALITY_PRESETS[2], // high
      }),
    );
    expect(settings.additionalFlags).toContain('-row-mt');
  });
});

