// ─── inferQualityFromBitrate Tests ─────────────────────────────────────

describe('inferQualityFromBitrate', () => {
  test('low bitrate = low quality', () => {
    const q = inferQualityFromBitrate(1000, 1920, 1080);
    expect(q.id).toBe('low');
  });

  test('standard bitrate = medium quality', () => {
    const q = inferQualityFromBitrate(8000, 1920, 1080);
    expect(q.id).toBe('medium');
  });

  test('high bitrate = high quality', () => {
    const q = inferQualityFromBitrate(12000, 1920, 1080);
    expect(q.id).toBe('high');
  });

  test('very high bitrate = ultra quality', () => {
    const q = inferQualityFromBitrate(20000, 1920, 1080);
    expect(q.id).toBe('ultra');
  });
});

// ─── validateExportConfig Tests ────────────────────────────────────────

describe('validateExportConfig', () => {
  const makeConfig = (overrides: Partial<ExportConfiguration> = {}): ExportConfiguration => ({
    resolution: RESOLUTION_PRESETS[2], // 1080p
    format: FORMAT_OPTIONS[0], // mp4
    quality: QUALITY_PRESETS[1], // medium
    codec: 'h264',
    fps: 30,
    customBitrateKbps: null,
    includeAudio: true,
    ...overrides,
  });

  test('valid config on pro plan returns valid=true', () => {
    const result = validateExportConfig(makeConfig(), 'pro', 60);
    expect(result.valid).toBe(true);
    expect(result.errors).toHaveLength(0);
  });

  test('4K on free plan returns error', () => {
    const result = validateExportConfig(
      makeConfig({ resolution: RESOLUTION_PRESETS[3] }),
      'free',
      60,
    );
    expect(result.valid).toBe(false);
    expect(result.errors.length).toBeGreaterThan(0);
    expect(result.errors[0]).toContain('Resolução');
  });

  test('webm on free plan returns error', () => {
    const result = validateExportConfig(
      makeConfig({ format: FORMAT_OPTIONS[1], resolution: RESOLUTION_PRESETS[1] }),
      'free',
      60,
    );
    expect(result.valid).toBe(false);
    expect(result.errors.some(e => e.includes('Formato'))).toBe(true);
  });

  test('duration exceeding plan limit returns error', () => {
    const result = validateExportConfig(
      makeConfig({ resolution: RESOLUTION_PRESETS[1] }),
      'free',
      300,
    );
    expect(result.valid).toBe(false);
    expect(result.errors.some(e => e.includes('Duração'))).toBe(true);
  });

  test('free plan adds watermark warning', () => {
    const result = validateExportConfig(
      makeConfig({ resolution: RESOLUTION_PRESETS[1] }),
      'free',
      30,
    );
    expect(result.valid).toBe(true);
    expect(result.warnings.length).toBeGreaterThan(0);
    expect(result.warnings[0]).toContain('marca d\'água');
  });

  test('large file size adds warning', () => {
    // 4K ultra with long duration
    const result = validateExportConfig(
      makeConfig({
        resolution: RESOLUTION_PRESETS[3],
        quality: QUALITY_PRESETS[3],
      }),
      'pro',
      3600, // 1 hour
    );
    expect(result.valid).toBe(true);
    expect(result.warnings.some(w => w.includes('2 GB'))).toBe(true);
  });
});

