// ─── estimateExportDuration Tests ──────────────────────────────────────

describe('estimateExportDuration', () => {
  test('returns positive for valid inputs', () => {
    expect(estimateExportDuration(60, 1920, 1080, 'medium')).toBeGreaterThan(0);
  });

  test('4K takes longer than 1080p', () => {
    const time1080 = estimateExportDuration(60, 1920, 1080, 'medium');
    const time4k = estimateExportDuration(60, 3840, 2160, 'medium');
    expect(time4k).toBeGreaterThan(time1080);
  });

  test('ultra quality takes longer than low', () => {
    const low = estimateExportDuration(60, 1920, 1080, 'low');
    const ultra = estimateExportDuration(60, 1920, 1080, 'ultra');
    expect(ultra).toBeGreaterThan(low);
  });
});

// ─── formatEstimatedDuration Tests ──────────────────────────────────────

describe('formatEstimatedDuration', () => {
  test('formats zero', () => {
    expect(formatEstimatedDuration(0)).toBe('< 1 segundo');
  });

  test('formats seconds', () => {
    expect(formatEstimatedDuration(30)).toBe('~30 segundos');
    expect(formatEstimatedDuration(1)).toBe('~1 segundo');
  });

  test('formats minutes', () => {
    expect(formatEstimatedDuration(90)).toBe('~2 minutos');
    expect(formatEstimatedDuration(60)).toBe('~1 minuto');
  });

  test('formats hours', () => {
    expect(formatEstimatedDuration(3600)).toBe('~1 hora');
    expect(formatEstimatedDuration(5400)).toBe('~1h 30min');
    expect(formatEstimatedDuration(7200)).toBe('~2 horas');
  });
});
